        let tool = make_tool();
        let add = tool
            .execute(json!({
                "action": "add",
                "job": {
                    "name": "to remove",
                    "schedule": { "kind": "every", "every_ms": 60000 },
                    "payload": { "kind": "agentTurn", "message": "x" },
                    "sessionTarget": "isolated"
                }
            }))
            .await
            .unwrap();

        let id = add["id"].as_str().unwrap();
        let result = tool
            .execute(json!({ "action": "remove", "id": id }))
