```rust
fn try_parse_stringified_object(value: Value) -> Value {
    if let Value::String(ref s) = value {
        if let Ok(parsed @ Value::Object(_)) = serde_json::from_str(s.trim()) {
            tracing::debug!(
                original = %s,
                "rescued double-serialised object parameter"
            );
            return parsed;
        }
    }
    value
}
